import { Component, OnInit } from '@angular/core';
import { ChatService } from './services/chat.service';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent implements OnInit {
  messages: any[] = [];
  userInput: string = '';
  isLoading: boolean = false;
  selectedFile: File | null = null;
  selectedProducts: any[] = [];
  showOrderConfirmation: boolean = false;
  orderConfirmation: any = null;
  context: any = {};

  constructor(private chatService: ChatService) {}

  ngOnInit(): void {
    this.chatService.messages$.subscribe(msgs => {
      this.messages = msgs;
      this.scrollToBottom();
    });
  }

  /**
   * Send message to agent
   */
  sendMessage(): void {
    if (!this.userInput.trim()) {
      return;
    }

    const userMessage = this.userInput;
    this.userInput = '';
    this.isLoading = true;

    // Add user message to UI
    this.chatService.addMessage('user', userMessage);

    // Send to backend
    this.chatService.sendMessage(userMessage, this.context).subscribe(
      (response: any) => {
        this.isLoading = false;

        // Add agent response
        this.chatService.addMessage('assistant', response.message);

        // Update context
        this.context = response.context || this.context;

        // Handle product recommendations
        if (response.productRecommendations) {
          this.selectedProducts = response.productRecommendations;
        }

        // Handle order confirmation
        if (response.type === 'order-confirmation') {
          this.orderConfirmation = response.orderData;
          this.showOrderConfirmation = true;
          setTimeout(() => this.showOrderConfirmation = false, 5000);
        }

        this.scrollToBottom();
      },
      (error: any) => {
        this.isLoading = false;
        console.error('Error:', error);
        this.chatService.addMessage('assistant', 'Sorry, an error occurred. Please try again.');
      }
    );
  }

  /**
   * Handle file selection
   */
  onFileSelected(event: any): void {
    const file: File = event.target.files[0];
    if (file) {
      this.selectedFile = file;
      this.uploadImage();
    }
  }

  /**
   * Upload image to agent
   */
  uploadImage(): void {
    if (!this.selectedFile) {
      return;
    }

    this.isLoading = true;
    const userMessage = `I'm uploading an image to find similar products`;
    this.chatService.addMessage('user', userMessage);

    this.chatService.uploadImage(this.selectedFile, 'Find products similar to this image').subscribe(
      (response: any) => {
        this.isLoading = false;
        this.chatService.addMessage('assistant', response.message);
        
        if (response.productRecommendations) {
          this.selectedProducts = response.productRecommendations;
        }

        this.selectedFile = null;
        this.scrollToBottom();
      },
      (error: any) => {
        this.isLoading = false;
        console.error('Error uploading image:', error);
        this.chatService.addMessage('assistant', 'Error processing image. Please try again.');
      }
    );
  }

  /**
   * Handle product selection (e.g., clicking on a product card)
   */
  selectProduct(productId: number): void {
    const product = this.selectedProducts.find(p => p.id === productId);
    if (product) {
      this.userInput = `I want to buy the ${product.name}`;
      this.sendMessage();
    }
  }

  /**
   * Reset conversation
   */
  resetConversation(): void {
    this.chatService.clearMessages();
    this.chatService.resetConversation().subscribe(
      () => {
        this.messages = [];
        this.selectedProducts = [];
        this.context = {};
      }
    );
  }

  /**
   * Scroll to bottom of chat
   */
  scrollToBottom(): void {
    setTimeout(() => {
      const chatContainer = document.querySelector('.chat-messages');
      if (chatContainer) {
        chatContainer.scrollTop = chatContainer.scrollHeight;
      }
    }, 100);
  }

  /**
   * Close order confirmation popup
   */
  closeOrderConfirmation(): void {
    this.showOrderConfirmation = false;
  }
}
<div class="app-container">
  <!-- Header -->
  <header class="app-header">
    <h1>🛍️ Shopping Agent Assistant</h1>
    <button (click)="resetConversation()" class="reset-btn">Reset Chat</button>
  </header>

  <!-- Main Container -->
  <div class="main-container">
    <!-- Chat Window -->
    <section class="chat-section">
      <div class="chat-messages" id="chatMessages">
        <div *ngFor="let msg of messages" [ngClass]="msg.role === 'user' ? 'user-message' : 'assistant-message'">
          <div class="message-content">
            {{ msg.content }}
          </div>
        </div>

        <div *ngIf="isLoading" class="loading-indicator">
          <span class="loader"></span> Agent is thinking...
        </div>
      </div>

      <!-- Input Area (Fixed at Bottom) -->
      <div class="input-area">
        <textarea 
          [(ngModel)]="userInput" 
          (keyup.enter)="sendMessage()"
          placeholder="Type your message... (e.g., 'Show me TVs above ₹50,000')"
          class="message-input">
        </textarea>

        <div class="input-controls">
          <button (click)="sendMessage()" [disabled]="isLoading || !userInput.trim()" class="send-btn">
            Send
          </button>

          <label class="upload-btn">
            📸 Upload Image
            <input type="file" 
                   accept="image/*" 
                   (change)="onFileSelected($event)" 
                   style="display:none;">
          </label>
        </div>
      </div>
    </section>

    <!-- Product Sidebar -->
    <aside class="product-sidebar" [ngClass]="selectedProducts?.length > 0 ? 'show' : 'hide'">
      <div *ngIf="selectedProducts && selectedProducts.length > 0">
        <h3>💡 Products</h3>
        <div class="product-list">
          <div *ngFor="let product of selectedProducts" 
               class="product-card"
               (click)="selectProduct(product.id)">
            <div class="product-name">{{ product.name }}</div>
            <div class="product-brand">{{ product.brand }}</div>
            <div class="product-price">₹{{ product.price }}</div>
            <div class="product-rating">⭐ {{ product.rating }}</div>
            <div class="product-stock" [ngClass]="product.inStock ? 'in-stock' : 'out-of-stock'">
              {{ product.inStock ? 'In Stock' : 'Out' }}
            </div>
          </div>
        </div>
      </div>
    </aside>
  </div>

  <!-- Order Confirmation Popup -->
  <div *ngIf="showOrderConfirmation" class="order-confirmation-popup">
    <div class="confirmation-content">
      <div class="confirmation-header">
        <h2>✅ Order Confirmed!</h2>
        <button (click)="closeOrderConfirmation()" class="close-btn">×</button>
      </div>
      <div class="confirmation-details">
        <p><strong>Order ID:</strong> {{ orderConfirmation?.orderId }}</p>
        <p><strong>Product:</strong> {{ orderConfirmation?.productName }}</p>
        <p><strong>Quantity:</strong> {{ orderConfirmation?.quantity }}</p>
        <p><strong>Total Price:</strong> ₹{{ orderConfirmation?.totalPrice }}</p>
        <p><strong>Estimated Delivery:</strong> {{ orderConfirmation?.estimatedDelivery }}</p>
      </div>
    </div>
  </div>
</div>
